parameters.jsCode:
const raw = $input.item.json.candidates[0].content.parts[0].text.trim();
const webhook = $('Webhook — /score').item.json;

let score = 0, reason = '', product = 'наставничество';

for (const line of raw.split('\n')) {
  const l = line.trim();
  if (l.startsWith('SCORE:')) {
    const n = parseInt(l.split(':', 1)[1] || l.replace('SCORE:', '').trim());
    if (!isNaN(n)) score = Math.max(0, Math.min(100, n));
  } else if (l.startsWith('ПРИЧИНА:')) {
    reason = l.split(':', 1)[1]?.trim() || l.replace('ПРИЧИНА:', '').trim();
  } else if (l.startsWith('ПРОДУКТ:')) {
    product = l.split(':', 1)[1]?.trim() || l.replace('ПРОДУКТ:', '').trim();
  }
}

return [{
  json: {
    lead_id: webhook.lead_id || null,
    name: webhook.name || '',
    niche: webhook.niche || '',
    score,
    reason,
    product,
    hot: score >= 80,
    contact: webhook.contact || '',
    raw_response: raw
  }
}];
